import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"暴走轻机枪","description":"","frontmatter":{},"headers":[],"relativePath":"7.UA/4.物品与装备/1.武器/暴走轻机枪.md","filePath":"7.UA/4.物品与装备/1.武器/暴走轻机枪.md"}'),d={name:"7.UA/4.物品与装备/1.武器/暴走轻机枪.md"};function _(l,a,p,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"暴走轻机枪",tabindex:"-1"},[s("暴走轻机枪 "),e("a",{class:"header-anchor",href:"#暴走轻机枪","aria-label":'Permalink to "暴走轻机枪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序002")])])],-1),o('<h1 id="暴走轻机枪-1" tabindex="-1">暴走轻机枪 <a class="header-anchor" href="#暴走轻机枪-1" aria-label="Permalink to &quot;暴走轻机枪&quot;">​</a></h1><p>持久的暴走轻机枪<br> （D+500）<br> “暴走这逼枪，除了烂成一坨屎的腰射，其他方面都挺不错的”<br> 暴走作为一款王勇防务（Wonyeon Defense）推出的全新旗舰款机枪，凭借其稳定可靠的性能，深受IMC和边境反抗军的喜爱。而由于其优异的性能，kg博士对其进行了一次改良，以便于其更加持久的作战。至于这次改动是否与宇宙作战者权益保护法冲突，就不在博士的考虑范围内了。<br> 于是，996作战就此诞生，战士们苦不堪言，军事家们则乐开了花，当然，这也是后话了......<br> --------------------------------------------------------------------------------------------------------------------<br> 这是一把造成6L伤害的轻机枪（步枪），装弹量为30，基础射程为150，可以进行短点射/长点射/连射，体积为3，使用和自动步枪一样的改造和弹药。<br> ［过载］：使用迅捷动作，将铝热剂手雷塞入枪身的存储器内中，使枪械过热，此时的枪械额外获得贯穿，和无限子弹和破甲1的特性，你在此状态下的攻击获得3dp的器械加值持续时间一轮<br> ［加班］在过载状态下，你永远不会感到疲惫，也不需要休息。<br> 6*1.25+5</p><p>铝热剂手雷<br> 250分/1枚<br> 铝热剂手雷最开始是什么人制作出来已经无从考究了，但从它在IMC和边境反抗军中的受欢迎程度中，可以看出这款堪称手雷在投掷物历史上的重要地位。</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
